INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (2108, 212278, 9, 164, '建议', '强烈建议最近一段时间以提高球队自身能力和整体配合作战能力为主，一方面由于天气实在太热，早上的比赛简直是活受罪；另一方面就是和对手比起来，我们的配合实在是太差了！场上所有人的跑位和接应好像都有问题，进球大多来自某一两个人的灵光一线，建议球队下一阶段可以分两个部分，一部分人参加基本功的强化和培训，另外一部分人参加全队的整体配合和套路演练，可素目前头疼的是没有套路可以练......', '强烈建议最近一段时间以提高球队自身能力和整体配合作战能力为主，一方面由于天气实在太热，早上的比赛简直是活受罪；另一方面就是和对手比起来，我们的配合实在是太差了！场上所有人的跑位和接应好像都有问题，进球大多来自某一两个人的灵光一线，建议球队下一阶段可以分两个部分，一部分人参加基本功的强化和培训，另外一部分人参加全队的整体配合和套路演练，可素目前头疼的是没有套路可以练......', NULL, '2003-08-31 20:04:00', 37, '20031003161202_bbsid_212278_board_9_91bbb75ab9.html', '20031003161202');
